# Terraform example: launch a Marketplace AMI after subscribing
data "aws_ami" "marketplace_product" {
  owners      = ["679593333241"]  # AWS Marketplace seller account
  most_recent = true

  filter {
    name   = "name"
    values = ["vendor-product-name-*"]
  }
}

resource "aws_instance" "vendor_appliance" {
  ami           = data.aws_ami.marketplace_product.id
  instance_type = "t3.medium"
  subnet_id     = var.private_subnet_id

  tags = {
    Name = "vendor-appliance"
  }
}

# Enable and configure Private Marketplace via AWS CLI
# Requires AWSPrivateMarketplaceAdminFullAccess permission

# Create a Private Marketplace experience
aws marketplace-catalog start-change-set \
    --catalog AWSMarketplace \
    --change-set '[{
        "ChangeType": "CreateExperience",
        "ChangeName": "CreatePrivateMarketplace",
        "Entity": {
            "Type": "Experience@1.0"
        },
        "Details": "{"Name": "Corporate Approved Products", "Status": "Live"}"
    }]'

# Add an approved product to Private Marketplace (by product ID)
aws marketplace-catalog start-change-set \
    --catalog AWSMarketplace \
    --change-set '[{
        "ChangeType": "AllowProductProcurement",
        "ChangeName": "ApproveProduct",
        "Entity": {
            "Type": "Experience@1.0",
            "Identifier": "exp-your-experience-id"
        },
        "Details": "{"ProductId": "prod-yourproductid"}"
    }]'

# IAM policy snippet: deny Marketplace subscription for developer roles
{
    "Version": "2012-10-17",
    "Statement": [
        {
            "Sid": "DenyMarketplaceSubscribe",
            "Effect": "Deny",
            "Action": [
                "aws-marketplace:Subscribe",
                "aws-marketplace:Unsubscribe"
            ],
            "Resource": "*"
        }
    ]
}
